return ['domain'=>'capability-manager-enhanced% 10 == 0) ? 2 : 3)));% 10 == 0) ? 2: 3)));','plural-forms'=>'nplurals=4; plural=(n == 1 ? 0 : (n == 2 ? 1 : ((n > 10 && n % 10 == 0) ? 2 : 3)));','language'=>'he_IL','project-id-version'=>'PublishPress Capabilities 2.42.0','pot-creation-date'=>'2026-04-19T15:36:09+00:00','po-revision-date'=>'2026-04-22 08:33+0000','x-generator'=>'WP-CLI 2.12.0','messages'=>['PublishPress Capabilities'=>'יכולות PublishPress','https://publishpress.com/capability-manager/'=>'https://publishpress.com/capability-manager/','PublishPress Capabilities is the access control plugin for WordPress. You can manage all your WordPress user roles, from Administrators to Subscribers.'=>'יכולות PublishPress הוא תוסף לשליטת גישה עבור WordPress. אתה יכול לנהל את כל תפקידי המשתמשים שלך ב-WordPress, מהמנהלים ועד המנויים.','PublishPress'=>'PublishPress','https://publishpress.com/'=>'https://publishpress.com/','%1s Error: %2s  PublishPress Capabilities cannot function because another copy of the plugin is active.'=>'%1s שגיאה: %2s  יכולות PublishPress אינן יכולות לפעול כי עותק אחר של התוסף פעיל.','This plugin can be deleted.'=>'תוסף זה ניתן למחיקה.','You can block pages by URL or hide Admin elements by entering a CSS class or ID. This feature is available in PublishPress Capabilities Pro.'=>'אתה יכול לחסום דפים לפי URL או להסתיר אלמנטים של מנהל על ידי הזנת מחלקת CSS או מזהה. תכונה זו זמינה ב-PublishPress Capabilities Pro.','Upgrade to Pro'=>'שדרג ל-Pro','Admin Menu Restrictions'=>'מגבלות תפריטי מנהל','You can restrict access to admin menu screens. You can also edit, change, add, or remove links from the WordPress admin menu. This feature is available in PublishPress Capabilities Pro.'=>'אתה יכול להגביל גישה למסכים בתפריט המנהל. אתה יכול גם לערוך, לשנות, להוסיף או להסיר קישורים מתפריט המנהל של WordPress. תכונה זו זמינה ב-PublishPress Capabilities Pro.','You\'re using PublishPress Capabilities Free. The Pro version has more features and support. %sUpgrade to Pro%s'=>'אתה משתמש ביכולות PublishPress חינם. גרסת Pro כוללת תכונות נוספות ותמיכה. %sשדרג ל-Pro%s','Admin Menus'=>'תפריטי מנהל','Hide CSS Elements'=>'הסתר אלמנטים CSS','Block by URL'=>'חסום לפי URL','Admin Menus allows you to edit the admin menu links and control who has access.'=>'תפריטי מנהל מאפשרים לך לערוך את הקישורים בתפריט המנהל ולשלוט מי יש לו גישה.','Select pages...'=>'בחר דפים...','You can select page types where this element will be added.'=>'אתה יכול לבחור סוגי דפים שבהם האלמנט הזה יתווסף.','Metaboxes'=>'מטה-תיבות','Checklist'=>'רשימת בדיקה','Editorial Comments'=>'הערות מערכת','Notifications'=>'התראות','TaxoPress - Settings'=>'TaxoPress - הגדרות','You can hide plugin metaboxes. You can also hide specific items by entering their CSS class or ID. This feature is available in PublishPress Capabilities Pro.'=>'אתה יכול להסתיר תיבות מידע של התוסף. אתה יכול גם להסתיר פריטים ספציפיים על ידי הזנת מחלקת ה-CSS או ה-ID שלהם. תכונה זו זמינה ב-PublishPress Capabilities Pro.','Custom Items'=>'פריטים מותאמים אישית','Custom item one'=>'פריט מותאם אישית אחד','Permalink: Descriptive Caption'=>'קישור קבוע: כותרת תיאורית','Page Attributes: Order'=>'מאפייני דף: סדר','You can use Frontend Features to target specific posts and pages. This feature is available in PublishPress Capabilities Pro.'=>'אתה יכול להשתמש בתכונות חיצוניות כדי למקד לפוסטים ודפים ספציפיים. תכונה זו זמינה ב-PublishPress Capabilities Pro.','Select post types...'=>'בחר סוגי פוסטים...','This will add a metabox on the post editing screen. You can use this feature to add body classes only for that post.'=>'זה יוסיף תיבת מידע על מסך עריכת הפוסט. אתה יכול להשתמש בתכונה זו כדי להוסיף מחלקות גוף רק לפוסט הזה.','Drag multiple roles selection to change roles order.'=>'גרור את הבחירה של תפקידים מרובים כדי לשנות את סדר התפקידים.','Page title'=>'כותרת דף','Rank Math SEO'=>'Rank Math SEO','Capabilities'=>'יכולות','No permission!'=>'אין הרשאה!','Invalid nonce token!'=>'אסימון nonce לא חוקי!','Error: wrong data'=>'שגיאה: נתונים שגויים','An error occured!'=>'אירעה שגיאה!','Security check failed'=>'בדיקת אבטחה נכשלה','Permission denied'=>'גישה נדחתה','Settings updated successfully.'=>'ההגדרות עודכנו בהצלחה.','Logged In Users'=>'משתמשים מחוברים','Logged Out Users'=>'משתמשים מנותקים','PublishPress Capabilities Menu Restriction'=>'הגבלות בתפריט יכולות PublishPress','This menu is restricted for the following roles'=>'תפריט זה מוגבל עבור התפקידים הבאים','Dashboard'=>'לוח בקרה','Roles'=>'תפקידים','Settings'=>'הגדרות','Success notices'=>'הודעות הצלחה','Error notices'=>'הודעות שגיאה','Warning notices'=>'הודעות אזהרה','Info notices'=>'הודעות מידע','Current Role'=>'תפקיד נוכחי','Admin Notices'=>'הודעות מנהל','Save for all Roles'=>'שמור עבור כל התפקידים','Save for %s'=>'שמור עבור %s','Notification center access'=>'גישה למרכז התראות','Enable %1$s access to the Admin Notices area.'=>'אפשר גישה ל-%1$s לאזור הודעות המנהל.','Notifications to remove from WordPress admin pages'=>'התראות להסרה מעמודי ניהול WordPress','Select the notification types that should be hidden when a user in the %1$s role is viewing WordPress admin screens.'=>'בחר את סוגי ההודעות שצריכים להיות מוסתרים כאשר משתמש בתפקיד %1$s צופה במסכים של WordPress admin.','Click here for more on notice types.'=>'לחץ כאן למידע נוסף על סוגי ההודעות.','Notifications to display in the Admin Notices area.'=>'הודעות שיוצגו באזור הודעות המנהל.','Select the notification types that should be displayed in the Admin Notices area after been removed from the WordPress admin screens.'=>'בחר את סוגי ההודעות שצריכים להיות מוצגים באזור הודעות המנהל לאחר שהוסרו ממסכים של WordPress admin.','Admin Notices allows you to clean up the WordPress admin area by organizing extra messages and advertisements into one place.'=>'הודעות המנהל מאפשרות לך לנקות את אזור המנהל של WordPress על ידי ארגון הודעות נוספות ופרסומות במקום אחד.','Features include:'=>'המאפיינים כוללים:','Move selected notice types out of admin pages'=>'העבר סוגי הודעות שנבחרו מתוך דפי המנהל','Show selected notices in a dedicated Admin Notices panel'=>'הצג הודעות שנבחרו בלוח הודעות המנהל המיועד','Configure notice visibility by user role'=>'הגדר את נראות ההודעה לפי תפקיד המשתמש','View Documentation'=>'צפה בתיעוד','How to use Admin Notices'=>'איך להשתמש בהודעות המנהל','Display this notice'=>'הצג הודעה זו','Silence this notice'=>'כבה הודעה זו','Hide this notice'=>'הסתר הודעה זו','Move to Hidden Notices'=>'העבר להודעות מוסתרות','Displayed notices will no longer be removed from admin pages.'=>'ההודעות שמוצגות לא יוסרו יותר מדפי המנהל.','This notice will be moved to the "Silenced Notices" tab and you will not receive a notification if it appears again.'=>'הודעה זו תועבר ללשונית "הודעות מושתקות" ואתה לא תקבל הודעה אם היא תופיע שוב.','Hidden Notices'=>'הודעות מוסתרות','Silenced Notices'=>'הודעות מושתקות','There are currently no admin notices.'=>'נכון לעכשיו אין הודעות מנהל.','Edit the settings.'=>'ערוך את ההגדרות.','You do not have permission to manage admin notices.'=>'אין לך הרשאה לנהל הודעות ניהול.','Invalid action. Reload this page and try again.'=>'פעולה לא חוקית. טען מחדש את הדף הזה וניסיון שוב.','Invalid form.'=>'טופס לא חוקי.','Admin notice status updated successfully.'=>'סטטוס הודעת הניהול עודכן בהצלחה.','Warning: This role cannot access the dashboard without the read capability. %1$sClick here to fix this now%2$s.'=>'אזהרה: תפקיד זה אינו יכול לגשת ל-dashboard ללא יכולת קריאה. %1$sלחץ כאן כדי לתקן את זה עכשיו%2$s.','Negate All'=>'מנוגד הכל','Negate None'=>'מנוגד אף אחד','Role Capabilities'=>'יכולות תפקיד','Search capabilities...'=>'חפש יכולות...','Nav Menus (Block)'=>'תפריטי ניווט (חסימה)','Block'=>'חסימה','Nav Menus (Legacy)'=>'תפריטי ניווט (מורשת)','Legacy'=>'מורשת','&nbsp;'=>'&nbsp;','Visibility'=>'נראות','Editing'=>'עריכה','Deletion'=>'מחיקה','Taxonomies'=>'taxonomies','Listing'=>'רשימה','Create Revision'=>'צור גרסה','Submit Revision'=>'שלח גרסה','Approve Revision'=>'אשר גרסה','Can read posts which are currently published with private visibility.'=>'יכול לקרוא פוסטים שפורסמו כרגע עם פרטיות פרטית.','Has basic editing capability (but may need other capabilities based on post status and ownership).'=>'יש לו יכולות עריכה בסיסיות (אך עשוי להזדקק ליכולות נוספות בהתאם למצב הפוסט ובעלות).','Can edit posts which were created by other users.'=>'יכול לערוך פוסטים שנוצרו על ידי משתמשים אחרים.','Can edit posts which are currently published.'=>'יכול לערוך פוסטים שפורסמו כרגע.','Can edit posts which are currently published with private visibility.'=>'יכול לערוך פוסטים שפורסמו כרגע עם פרטיות פרטית.','Can make a post publicly visible.'=>'יכול להפוך פוסט לגלוי לציבור.','Has basic deletion capability (but may need other capabilities based on post status and ownership).'=>'יש לו יכולות מחיקה בסיסיות (אך עשוי להזדקק ליכולות נוספות בהתאם למצב הפוסט ובעלות).','Can delete posts which were created by other users.'=>'יכול למחוק פוסטים שנוצרו על ידי משתמשים אחרים.','Can delete posts which are currently published.'=>'יכול למחוק פוסטים שפורסמו כרגע.','Can delete posts which are currently published with private visibility.'=>'יכול למחוק פוסטים שפורסמו כרגע עם פרטיות פרטית.','Multisite'=>'Multisite','Admin'=>'Admin','Invalid Capabilities'=>'יכולות לא חוקיות','Additional'=>'נוסף','Term %s Capabilities'=>'מונח %s יכולות','%s Capabilities'=>'%s יכולות','Post %s Capabilities'=>'פוסט %s יכולות','Taxonomy'=>'Taxonomy','Filter by taxonomy'=>'סנן לפי taxonomy','Filter by post type'=>'סנן לפי post type','The slug for this taxonomy is %s'=>'ה-slug עבור taxonomy זה הוא %s','The slug for this post type is %s'=>'ה-slug עבור post type זה הוא %s','%s: assigned by Permission Group'=>'%s: הוקצה על ידי קבוצת הרשאות','This capability is %s'=>'היכולת הזו היא %s','This capability is controlled by %s'=>'היכולת הזו נשלטת על ידי %s','This capability is controlled by %s Use the sidebar settings to allow this to be controlled independently.'=>'היכולת הזו נשלטת על ידי %s השתמש בהגדרות הצד כדי לאפשר זאת להיות נשלט באופן עצמאי.','Use the sidebar settings to allow this to be controlled independently.'=>'שימוש בהגדרות הצד כדי לאפשר זאת להיות נשלט באופן עצמאי.','This capability is not available for this post type.'=>'היכולת הזו אינה זמינה עבור post type זה.','Admin listing access is normally provided by the "Edit" capabilities. These "List" capabilities only apply if the corresponding "Edit" capability is missing. Also, these "List" capabilities can grant access, but not deny access.'=>'גישה לרשימת מנהל ניתנת בדרך כלל על ידי יכולות "עריכה". יכולות "רשימה" אלו חלות רק אם היכולת "עריכה" המתאימה חסרה. כמו כן, יכולות "רשימה" אלו יכולות להעניק גישה, אך לא לשלול גישה.','Filter by capability'=>'סנן לפי יכולת','No results found. Please try again with a different word.'=>'לא נמצאו תוצאות. אנא נסה שוב עם מילה אחרת.','check / uncheck all'=>'סמן / בטל סימון הכל','Capability Name'=>'שם היכולת','WordPress Core Capabilities'=>'יכולות הליבה של WordPress','General'=>'כללי','Plugin Capabilities &ndash; %s'=>'יכולות פלאגין &ndash; %s','The User Testing feature also requires the %1$s edit_users %2$s capability.'=>'תכונת בדיקות המשתמשים דורשת גם את %1$s edit_users %2$s capability.','The following entries have no effect. Please assign desired capabilities on the Editing / Deletion / Private tabs.'=>'הכניסות הבאות אינן משפיעות. אנא הקצו את ההרשאות הרצויות בלשוניות עריכה / מחיקה / פרטיות.','Additional Capabilities'=>'הרשאות נוספות','You have no additional capabilities.'=>'אין לך הרשאות נוספות.','Capabilities allows you change the permissions for any user role.'=>'הרשאות מאפשרות לך לשנות את ההרשאות עבור כל תפקיד משתמש.','%1$s = Capability granted %2$s'=>'%1$s = הרשאה שניתנה %2$s','usage key'=>'מפתח שימוש','%1$s = Capability not granted %2$s'=>'%1$s = הרשאה לא ניתנה %2$s','%1$s = Capability denied, even if granted by another role %2$s'=>'%1$s = הרשאה נדחתה, גם אם ניתנה על ידי תפקיד אחר %2$s','You can also configure this role as a %sPermission Group%s.'=>'אתה יכול גם להגדיר תפקיד זה כ-%sקבוצת הרשאות%s.','How to use Capabilities'=>'איך להשתמש בהרשאות','Capabilities is Safe to Use'=>'הרשאות בטוחות לשימוש','WordPress stores role capabilities in your database, where they remain even if the plugin is deactivated.'=>'WordPress שומרת הרשאות תפקידים במסד הנתונים שלך, שם הן נשארות גם אם הפלאגין מושבת.','Whenever you use PublishPress Capabilities to save changes, it also creates a backup which you can use to restore a previous configuration.'=>'בכל פעם שאתה משתמש בהרשאות PublishPress כדי לשמור שינויים, הוא גם יוצר גיבוי שבו תוכל להשתמש כדי לשחזר קונפיגורציה קודמת.','Go to the Backup feature'=>'לך לתכונת הגיבוי','Add a New Capability'=>'הוסף הרשאה חדשה','Add to role'=>'הוסף לתפקיד','New capabilities are controlled on the Additonal tab.'=>'הרשאות חדשות נשלטות בלשונית נוספות.','PublishPress Permissions'=>'הרשאות PublishPress','Automatically define type-specific capabilities for your custom post types and taxonomies'=>'מגדיר אוטומטית הרשאות ספציפיות לסוג עבור סוגי הפוסטים והטקסונומיות המותאמות שלך','Assign standard WP roles supplementally for a specific post type'=>'הקצה תפקידי WP סטנדרטיים בנוסף עבור סוג פוסט ספציפי','Assign custom WP roles supplementally for a specific post type <em>(Pro)</em>'=>'הקצה תפקידים מותאמים אישית של WP בנוסף לסוג פוסט ספציפי <em>(Pro)</em>','Customize reading permissions per-category or per-post'=>'התאם אישית הרשאות קריאה לפי קטגוריה או לפי פוסט','Customize editing permissions per-category or per-post <em>(Pro)</em>'=>'התאם אישית הרשאות עריכה לפי קטגוריה או לפי פוסט <em>(Pro)</em>','Custom Post Visibility statuses, fully implemented throughout wp-admin <em>(Pro)</em>'=>'סטטוסי נראות פוסט מותאמים, מיושמים לחלוטין ברחבי wp-admin <em>(Pro)</em>','Custom Moderation statuses for access-controlled, multi-step publishing workflow <em>(Pro)</em>'=>'סטטוסי מ moderation מותאמים לעבודה עם זרימת פרסום בשלבים עם בקרת גישה <em>(Pro)</em>','Regulate permissions for Edit Flow post statuses <em>(Pro)</em>'=>'הוסדר הרשאות עבור סטטוסים של Edit Flow <em>(Pro)</em>','Customize the moderated editing of published content with Revisionary or Post Forking <em>(Pro)</em>'=>'התאם אישית את העריכה המנוהלת של תוכן שפורסם עם Revisionary או Post Forking <em>(Pro)</em>','Grant Spectator, Participant or Moderator access to specific bbPress forums <em>(Pro)</em>'=>'הענק גישה לספקן, משתתף או מודרטור לפורומים ספציפיים של bbPress <em>(Pro)</em>','Grant supplemental content permissions to a BuddyPress group <em>(Pro)</em>'=>'הענק הרשאות תוכן נוספות לקבוצת BuddyPress <em>(Pro)</em>','WPML integration to mirror permissions to translations <em>(Pro)</em>'=>'אינטגרציה של WPML לשכפול הרשאות לתרגומים <em>(Pro)</em>','Member support forum'=>'פורום תמיכה לחברים','%1$sgrab%2$s %3$s'=>'%1$sgrab%2$s %3$s','%s (free install)'=>'%s (התקנה חינם)','%1$sbuy%2$s %3$s'=>'%1$sbuy%2$s %3$s','%s info/purchase'=>'%s מידע/רכישה','Role level is mostly deprecated. However, it still determines eligibility for Post Author assignment and limits the application of user editing capabilities.'=>'רמת התפקיד בדרך כלל אינה בשימוש. עם זאת, היא עדיין קובעת את הזכאות להקצאת מחבר פוסט ומגבילה את יישום יכולות העריכה של משתמשים.','Level:'=>'רמה:','Create this role definition in new (future) sites'=>'צור את הגדרת התפקיד הזו באתרי (עתיד) חדשים','Include in new sites.'=>'כלול באתרי חדשים.','Copy / update this role definition to all sites now'=>'העתק / עדכן את הגדרת התפקיד הזו לכל האתרים עכשיו','Sync role to all sites.'=>'סנכרן תפקידים לכל האתרים.','Copy option settings to all sites now'=>'העתק הגדרות אפשרויות לכל האתרים עכשיו','Sync options to all sites.'=>'סנכרן אפשרויות לכל האתרים.','You do not have permission to restore backup.'=>'אין לך הרשאה לשחזר גיבוי.','New backup saved.'=>'גיבוי חדש נשמר.','Roles and Capabilities restored from initial backup.'=>'תפקידים והיכולות שוחזרו מהגיבוי הראשוני.','Restore failed. No backup found.'=>'שחזור נכשל. לא נמצאה גיבוי.','%s restored from last backup.'=>'%s שוחזר מהגיבוי האחרון.','Roles and Capabilities restored from selected auto-backup.'=>'תפקידים והיכולות שוחזרו מהגיבוי האוטומטי שנבחר.','Please upload a file to import'=>'אנא העלה קובץ לייבוא','Please upload a valid .json file'=>'אנא העלה קובץ .json תקף','Error importing settings! Please try again.'=>'שגיאה בייבוא הגדרות! אנא נסה שוב.','Error importing settings! Please check that you uploaded a valid json file.'=>'שגיאה בייבוא הגדרות! אנא ודא שהעלית קובץ json תקף.','%s successfully imported from uploaded data.'=>'%s יובא בהצלחה מהנתונים שהועלו.','Needed function to create default roles not found!'=>'פונקציה נדרשת ליצירת תפקידים ברירת מחדל לא נמצאה!','Roles and Capabilities reset to WordPress defaults'=>'תפקידים והיכולות הוחזרו לברירות המחדל של WordPress','Backup Tool for PublishPress Capabilities'=>'כלי גיבוי עבור היכולות של PublishPress','Restore'=>'שחזור','Backup'=>'גיבוי','Reset Roles'=>'איפוס תפקידים','Export / Import'=>'ייצוא / ייבוא','Backup Roles and Capabilities'=>'גיבוי תפקידים ויכולות','PublishPress Capabilities automatically creates a backup on installation and whenever you save changes. The initial backup and last %d auto-backups are kept.'=>'PublishPress Capabilities יוצר אוטומטית גיבוי בעת ההתקנה ובכל פעם שאתה שומר שינויים. הגיבוי הראשוני והאחרונים %d גיבויים אוטומטיים נשמרים.','A backup created on this screen replaces any previous manual backups, but is never automatically replaced.'=>'גיבוי שנוצר במסך זה מחליף כל גיבוי ידני קודם, אך אף פעם לא מוחלף אוטומטית.','Manual Backup'=>'גיבוי ידני','Last Manual Backup - %s'=>'גיבוי ידני אחרון - %s','Last Backup'=>'גיבוי אחרון','Restore Previous Roles and Capabilities'=>'שחזור תפקידים ויכולות קודמים','PublishPress Capabilities automatically creates a backup on installation and whenever you save changes.'=>'PublishPress Capabilities יוצר אוטומטית גיבוי בעת ההתקנה ובכל פעם שאתה שומר שינויים.','On this screen, you can restore an earlier version of your roles and capabilities.'=>'על המסך הזה, אתה יכול לשחזר גרסה קודמת של התפקידים והיכולות שלך.','Available Backups:'=>'גיבויים זמינים:','all roles'=>'כל התפקידים','Manual backup of %s (%s)'=>'גיבוי ידני של %s (%s)','Auto-backup of all roles (%s)'=>'גיבוי אוטומטי של כל התפקידים (%s)','Initial backup of all roles'=>'גיבוי ראשוני של כל התפקידים','Restore Selected Roles'=>'שחזור תפקידים שנבחרו','Show changes from current roles only'=>'הצג שינויים מהתפקידים הנוכחיים בלבד','Initial Backup - %s'=>'גיבוי ראשוני - %s','Initial Backup'=>'גיבוי ראשוני','%s (%s roles)'=>'%s (%s תפקידים)','(this role will be removed if you restore backup)'=>'(תפקיד זה יימחק אם תחדש גיבוי)','%s (level %s)'=>'%s (רמה %s)','No changes'=>'אין שינויים','Reset WordPress Defaults'=>'איפוס ברירות המחדל של WordPress','Warning:'=>'אזהרה:','Reseting default Roles and Capabilities will set them to the WordPress install defaults.'=>'איפוס תפקידים ויכולת ברירת המחדל יגדיר אותם לברירות המחדל של התקנת WordPress.','If you have installed any plugin that adds new roles or capabilities, these will be lost.'=>'אם התקנת תוסף כלשהו שמוסיף תפקידים או יכולות חדשות, אלה יאבדו.','It is recommended to use this only as a last resource!'=>'מומלץ להשתמש בזה רק כאמצעי אחרון!','Reset Roles and Capabilities to WordPress defaults'=>'איפוס תפקידים ויכולות לברירות המחדל של WordPress','You are about to reset Roles and Capabilities to WordPress defaults.
 \'Cancel\' to stop, \'OK\' to reset.'=>'אתה עומד לאפס תפקידים ויכולות לברירות המחדל של WordPress.
 \'ביטול\' כדי לעצור, \'אוקי\' כדי לאפס.','Reset to WordPress defaults'=>'איפוס לברירות המחדל של WordPress','Export Settings'=>'ייצוא הגדרות','Export the plugin settings for this site as a .json file. This allows you to easily import the configuration into another site.'=>'ייצא את הגדרות התוסף לאתר זה כקובץ .json. זה מאפשר לך לייבא בקלות את התצורה לאתר אחר.','Roles and Capabilities'=>'תפקידים ויכולות','Export'=>'ייצוא','Import Settings'=>'ייבוא הגדרות','Please make a \'Manual Backup\' in the backup tab to enable backup restore in case anything goes wrong.'=>'אנא צור \'גיבוי ידני\' בלשונית הגיבוי כדי לאפשר שחזור גיבוי במקרה שמשהו משתבש.','Import the plugin settings from a .json file. This file can be obtained by exporting the settings on another site using the form above.'=>'ייבא את הגדרות התוסף מקובץ .json. קובץ זה ניתן להשגה על ידי ייצוא ההגדרות באתר אחר באמצעות הטופס למעלה.','Before importing, we recommend using the "Backup" tab to create a backup of your current settings.'=>'לפני הייבוא, אנו ממליצים להשתמש בלשונית "גיבוי" כדי ליצור גיבוי של ההגדרות הנוכחיות שלך.','Admin Feature Restrictions'=>'מגבלות תכונת מנהל','Toggle all'=>'הפעל הכל','Wildcard enabled'=>'אופציית תו-דונק מופעלת','URL targeted'=>'כתובת URL ממוקדת','URL wildcard'=>'כתובת URL עם תו-דונק','Edit'=>'עריכה','Admin Features allows you to remove elements from the admin area and toolbar.'=>'תכונות מנהל מאפשרות לך להסיר אלמנטים מאזור המנהל ופס הכלים.','No change'=>'אין שינוי','This feature is denied'=>'תכונה זו נדחתה','How to use Admin Features'=>'איך להשתמש בתכונות מנהל','Admin Features Settings'=>'הגדרות תכונות מנהל','Hide Submenus'=>'הסתר תפריטים משנה','Select a preset font family'=>'בחר משפחת גופנים מוגדרת מראש','Custom style "%s" saved successfully.'=>'סגנון מותאם "%s" נשמר בהצלחה.','Custom style "%s" deleted successfully.'=>'סגנון מותאם "%s" נמחק בהצלחה.','Custom style name cannot be empty.'=>'שם הסגנון המותאם לא יכול להיות ריק.','Admin styles saved successfully.'=>'סגנונות מנהל נשמרו בהצלחה.','Admin Styles'=>'סגנונות מנהל','Setting'=>'הגדרה','Value'=>'ערך','Admin Color Scheme'=>'שיטת צבעים של מנהל','Sets the admin color scheme for all users. Click a scheme to preview it instantly.'=>'קובע את צבעי הניהול לכל המשתמשים. לחץ על ערכת צבעים כדי להציג אותה מיד.','Start from template'=>'התחל מתבנית','Blank Template'=>'תבנית ריקה','Add Custom Style'=>'הוסף סגנון מותאם אישית','Edit custom style'=>'ערוך סגנון מותאם אישית','Edit Color Style'=>'ערוך סגנון צבע','Customize colors for different admin elements. Changes are previewed instantly.'=>'התאם צבעים עבור אלמנטים שונים של הניהול. השינויים מוצגים מיד.','Add more than one custom admin styles. This feature is available in PublishPress Capabilities Pro.'=>'הוסף יותר מסגנון ניהול מותאם אחד. תכונה זו זמינה ב-PublishPress Capabilities Pro.','Add CSS selectors (class or ID), choose a style variation, and set a brand color.'=>'הוסף בוחרי CSS (מחלקה או מזהה), בחר גרסת סגנון, וקבע צבע מותג.','Add New Element'=>'הוסף אלמנט חדש','Selector'=>'בחר','e.g. .publishpress-wrap h1, #my-plugin-header'=>'למשל .publishpress-wrap h1, #my-plugin-header','Variation'=>'גרסה','Background'=>'רקע','Text'=>'טקסט','Border'=>'גבול','Brand Color'=>'צבע מותג','Remove'=>'הסר','Custom Style Name'=>'שם סגנון מותאם','e.g., Company Branding, Dark Mode'=>'למשל, מיתוג חברה, מצב כהה','Cancel'=>'ביטול','Delete Custom Style'=>'מחק סגנון מותאם אישית','Are you sure you want to delete this %1s? %2s %3s'=>'האם אתה בטוח שברצונך למחוק את ה-%1s הזה? %2s %3s','Custom Style'=>'סגנון מותאם אישית','Save Custom Style'=>'שמור סגנון מותאם אישית','Custom Admin Logo'=>'לוגו מנהל מותאם אישית','Upload a custom logo to replace the WordPress icon in the admin bar. Recommended: 20px by 20px in SVG or PNG format.'=>'העלא לוגו מותאם אישית כדי להחליף את סמל WordPress בשורת הניהול. מומלץ: 20px על 20px בפורמט SVG או PNG.','Select Image'=>'בחר תמונה','Custom Favicon'=>'favicon מותאם אישית','Upload a custom favicon for the admin area. Recommended: 16px by 16px or 32px by 32px in SVG or PNG format.'=>'העלא favicon מותאם אישית לאזור הניהול. מומלץ: 16px על 16px או 32px על 32px בפורמט SVG או PNG.','Admin Font Family'=>'משפחת גופנים של מנהל','Set a font stack for the admin area, for example "Segoe UI", sans-serif.'=>'קבע ערימת גופנים לאזור הניהול, לדוגמה "Segoe UI", sans-serif.','Preset Fonts'=>'גופנים מוכנים','Custom Value'=>'ערך מותאם אישית','Admin Font Size'=>'גודל גופן מנהל','Set a base font size for the admin area. Leave empty to use the default WordPress size.'=>'קבע גודל גופן בסיסי לאזור הניהול. השאר ריק כדי להשתמש בגודל ברירת המחדל של WordPress.','Default'=>'ברירת מחדל','Named Sizes'=>'גדלים עם שם','Pixel Sizes'=>'גדלים בפיקסלים','Typography Overrides'=>'הגדרות טיפוגרפיה','Optional target-specific typography rules for common admin elements.'=>'כללים אופציונליים ספציפיים למטרה עבור אלמנטים נפוצים במנהל.','Body Text'=>'טקסט גוף','Links'=>'קישורים','Headings'=>'כותרות','Admin Menu'=>'תפריט מנהל','Admin Bar'=>'שורת מנהל','Form Fields'=>'שדות טופס','Buttons'=>'כפתורים','Target'=>'מטרה','Font Family'=>'משפחת גופנים','Font Size'=>'גודל גופן','Preset'=>'הגדרה מראש','Custom'=>'מותאם אישית','Admin Footer Text'=>'טקסט תחתון למנהל','Replace the default "Thanks for creating with WordPress" message in the admin footer.'=>'החלף את הודעת ברירת המחדל "תודה על היצירה עם WordPress" בתחתית המנהל.','Replace "Howdy"'=>'החלף "שלום"','Replace "Howdy" in the admin bar.'=>'החלף "שלום" בשורת המנהל.','Control Settings'=>'הגדרות בקרת','Control how admin styles are applied to users.'=>'בקרת איך סגנונות המנהל מוחלים על משתמשים.','Hide Admin Color Scheme settings in user profile'=>'הסתר הגדרות סקימת צבעי מנהל בפרופיל המשתמש','When enabled, users cannot see or change color scheme settings in their profile. Role-based settings will be applied.'=>'כאשר זה מופעל, משתמשים לא יכולים לראות או לשנות הגדרות סקימת צבעים בפרופיל שלהם. הגדרות מבוססות תפקיד ייושמו.','Force role settings (override user selection)'=>'כפה הגדרות תפקיד (עזוב את בחירת המשתמש)','When enabled, role settings will always apply, overriding any user selection even if the color scheme UI is visible to them.'=>'כאשר זה מופעל, הגדרות התפקיד יחולו תמיד, עבירות כל בחירת משתמש גם אם ממשק הצבעים גלוי להם.','Admin Styles allows you to customize the WordPress admin area with your own branding.'=>'Admin Styles מאפשר לך להתאים אישית את אזור הניהול של WordPress עם המיתוג שלך.','Custom admin color schemes'=>'סקימות צבע מותאמות אישית לניהול','Replace the WordPress logo and favicon'=>'החלף את הלוגו של WordPress ואת ה-favicon','Custom footer text'=>'טקסט תחתון מותאם אישית','Replace "Howdy" text'=>'החלף את טקסט "Howdy"','How to use Admin Styles'=>'איך להשתמש ב-Admin Styles','Security check failed.'=>'בדיקת אבטחה נכשלה.','You do not have permission to manage admin styles.'=>'אין לך הרשאה לנהל את סגנונות הניהול.','No role specified.'=>'לא צוין תפקיד.','Use this Image'=>'השתמש בתמונה זו','Saving...'=>'שומר...','Settings saved.'=>'ההגדרות נשמרו.','Current logo preview'=>'תצוגה מקדימה של הלוגו הנוכחי','Add New Custom Style'=>'הוסף סגנון מותאם חדש','Edit Custom Style'=>'ערוך סגנון מותאם','Are you sure you want to delete "%s" custom style?'=>'האם אתה בטוח שאתה רוצה למחוק את הסגנון המותאם "%s"?','this custom style'=>'סגנון מותאם זה','Primary Button'=>'כפתור ראשי','Hover State'=>'מצב ריחוף','Notification'=>'התראה','Live preview of your custom color scheme'=>'תצוגה חיה של סכמת הצבעים המותאמת שלך','Custom Style Name is required.'=>'שם הסגנון המותאם נדרש.','Main Admin Color is required.'=>'צבע המנהל הראשי נדרש.','PublishPress Custom'=>'PublishPress Custom','Display Name'=>'שם תצוגה','Change how this style is displayed'=>'שנה כיצד הסגנון הזה מוצג','Enter a name for your custom style'=>'הזן שם עבור הסגנון המותאם שלך','Forest'=>'יער','Mint Breeze'=>'רוח מנטה','Cherry'=>'דובדבן','Graphite'=>'גרפיט','Midnight Teal'=>'טיל חצות','Sunrise'=>'זריחה','Desert Sand'=>'חול מדברי','Amber Glow'=>'זוהר ענבר','Citrus'=>'סיטרוס','Ocean Deep'=>'אוקיאנוס עמוק','Sage'=>'מרווה','Modern Slate'=>'Slate מודרני','Royal Plum'=>'שזיף מל